    def parse_trade(self, rawTrade: dict, market: Market = None) -> Trade:
        trade = self.safe_trade(self.extend({'info': rawTrade}, rawTrade))
        trade['id'] = ''
        trade['order'] = None
        trade['takerOrMaker'] = None
        trade['timestamp'] = self.safe_integer(rawTrade, 'timestamp')
        return trade

